55	const BASE_PREMIUM: Record<string, number> = {
56	  sword: 100,
57	  amulet: 60,
58	  staff: 80,
59	  potion: 40,
60	  rune: 25,
61	};
62	
63	const COMPONENT_PRICE = 25;
64	const BLOCK_SIZE = 3;
65	const BLOCK_PRICE = 60;
66	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
67	
68	const INITIAL_ASSESSMENT_RATE = 0.1;
69	const CURSE_SURCHARGE_RATE = 0.5;
70	const HIGH_ENCHANTMENT_RATE = 0.3;
71	const HIGH_ENCHANTMENT_THRESHOLD = 5;
72	const LOYALTY_DISCOUNT_RATE = 0.2;
73	const LOYALTY_YEARS_THRESHOLD = 2;
74	const PROCESSING_FEE = 5;
75	const FLOAT_PRECISION_DIGITS = 6;
76	
77	const itemOwnBase = (item: Item): number => {
78	  return COMPONENT_TYPES.has(item.type)
79	    ? COMPONENT_PRICE
80	    : BASE_PREMIUM[item.type];
81	};
82	
83	const itemSurcharge = (item: Item): number => {
84	  const own = itemOwnBase(item);
85	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * own : 0;
86	  const highEnchantment =
87	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
88	      ? HIGH_ENCHANTMENT_RATE * own
89	      : 0;
90	  return curse + highEnchantment;
91	};
92	
93	const componentBase = (count: number): number => {
94	  return count === BLOCK_SIZE ? BLOCK_PRICE : count * COMPONENT_PRICE;
95	};
96	
97	const countByType = (items: Item[]): Map<string, number> => {
98	  const counts = new Map<string, number>();
99	  for (const item of items) {
100	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
101	  }
102	  return counts;
103	};
104	
105	const itemBaseTotal = (items: Item[]): number => {
106	  let total = 0;
107	  for (const [type, count] of countByType(items)) {
108	    total += COMPONENT_TYPES.has(type)
109	      ? componentBase(count)
110	      : BASE_PREMIUM[type] * count;
111	  }
112	  return total;
113	};
114	
115	const quotePremium = (step: QuoteStep, customer: Customer): number => {
116	  const policyBase = itemBaseTotal(step.items);
117	  const surcharges = step.items.reduce(
118	    (sum, item) => sum + itemSurcharge(item),
119	    0,
120	  );
121	  const initialAssessment = INITIAL_ASSESSMENT_RATE * policyBase;
122	  const loyaltyDiscount =
123	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
124	      ? LOYALTY_DISCOUNT_RATE * policyBase
125	      : 0;
126	  const premium =
127	    policyBase + surcharges + initialAssessment - loyaltyDiscount + PROCESSING_FEE;
128	  return Math.ceil(Number(premium.toFixed(FLOAT_PRECISION_DIGITS)));
129	};
130	
131	export const runScenario = (scenario: Scenario): ScenarioResult => {
132	  return {
133	    results: scenario.steps.map((step) => ({
134	      premium: quotePremium(step as QuoteStep, scenario.customer),
135	    })),
136	  };
137	};
